{
  "name": "Low-Income Home Energy Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income must not exceed 150% of the federal poverty level. Limits for 2025: 1 person $1,956/month; 2 people $2,644/month; 3 people $3,331/month; 4 people $4,018/month; 5 people $4,707/month; 6 people $5,394/month. Adds ~$687 per additional person. Automatic eligibility if household receives SNAP, SSI, TANF, or certain veterans' benefits.",
    "asset_limits": "No asset limit applies.",
    "other_requirements": ["Household must have a heating or cooling expense.", "For crisis/cooling: Must face heating emergency (e.g., lack of heat, imminent utility cut-off, inoperable heating equipment) or have at least one vulnerable member (elderly 60+, disabled individual, or child under age 6).", "Households with members 60+ receive priority/preference.", "U.S. citizens, qualified aliens, and legal residents eligible."]
  },
  "benefits": {
    "type": "financial",
    "value": "Regular heating: $198-$703 one-time payment to utility. Cooling: $50-$700. Crisis (winter): up to $4,200; summer crisis not available. Payments go directly to utility company.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: commonhelp.virginia.gov (screen and apply)", "Phone: 855-635-4370 (Mon-Fri 7am-6pm)", "In-person/mail/fax: Local department of social services (find at dss.virginia.gov/localagency)"],
    "processing_time": "Notification in late December for some components; varies by type and local agency.",
    "waitlist": "Possible during high-demand periods; crisis applications prioritized but may close (e.g., regular crisis Nov 1-Mar 15, fuel crisis Jan 2-Mar 15).",
    "forms": ["Energy Assistance (EA) applications available via CommonHelp or local DSS; specific forms for fuel, crisis, cooling at dss.virginia.gov/benefit/ea/"],
    "documents": ["Recent utility bills", "Proof of income (Social Security, payroll, unemployment, pension, disability)", "Proof of address (rent receipt, lease, deed, property tax bill)", "Social Security numbers for all household members", "Proof of citizenship/legal residency (birth certificates, etc.)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all Virginia households meeting criteria.",
    "regional_variations": "Administered by local departments of social services; processing times and availability may vary by locality. Contact local DSS for specifics.",
    "offices_or_providers": ["Local departments of social services (full list at dss.virginia.gov/localagency)"]
  },
  "official_source": "https://www.dss.virginia.gov/benefit/ea/",
  "gotchas": ["Must reapply annually even if previously approved.", "Household includes all at address sharing utility (e.g., roommates count).", "Crisis programs have seasonal windows and may close early.", "Eligibility doesn't guarantee benefits; funding limited.", "Utility provider must participate.", "Public/subsidized housing eligibility depends on how energy costs are paid."],
  "data_shape_notes": "Benefits vary by component (regular, crisis, cooling) and priority (e.g., elderly/disabled); income at exactly 150% FPL; local DSS administration leads to regional processing variations; no asset test."
}

{
