  },
  "application": {
    "methods": ["Phone: 1-800-552-3402[7][8]", "Website: www.vda.virginia.gov[8]", "In-person or local: Through Virginia Insurance Counseling and Assistance Program (VICAP) network, e.g., Fairfax County at 703-324-5851[3][10]", "Email: aging@vda.virginia.gov[8]"],
