    "waitlist": null,
    "forms": ["No specific application form; contact for counseling session[1][2]"],
    "documents": ["Medicare card, current insurance details, questions about coverage (recommended but not required)[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to Virginia Medicare beneficiaries[3][7]",
    "regional_variations": "Delivered through local networks of area agencies on aging, senior centers, and community partners; locally focused on regional Medicare options and resources[2][5]",
