    "asset_limits": "Low resources required (e.g., Central Virginia); specific dollar limits not detailed. What counts: generally countable assets like bank accounts; exemptions not specified but follow standard legal aid low-resource guidelines.",
    "other_requirements": ["U.S. citizenship or eligible immigration status", "Live in or have legal problem in service area of specific legal aid society", "Civil legal issue in covered areas (e.g., elder law, public benefits, housing, abuse)", "Not for domestic violence, prisoners, or community groups in some programs"]
  },
  "benefits": {
    "type": "service",
    "value": "Free civil legal advice and representation in elder law areas including power of attorney, long-term care, public benefits (Medicaid, SSI), guardianship alternatives, age discrimination, financial exploitation, abuse/neglect, housing, consumer issues. No specific dollar amounts or hours; full representation or advice as case allows.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Statewide Senior Legal Helpline (844) 802-5910 (toll-free for Virginians 60+)", "Phone: Regional examples - Central Virginia Legal Aid Society: Local 804-648-1012, Toll-free 800-868-1012 or 866-534-5243", "Website: valegalaid.org to locate local program", "In-person: Local legal aid offices (e.g., Central Virginia); bring documents to appointment", "Phone: Virginia Legal Services referral 800-552-7977"],
    "processing_time": "Not specified",
    "waitlist": "Not specified; limited lawyers may cause delays",
    "forms": ["No specific form names/numbers; intake via phone, have case papers ready"],
    "documents": ["Papers related to your case", "Proof of income, resources, age, residency, citizenship/immigration status"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Served by 9 regional legal aid societies; must contact local program for service area (e.g., Southwest Virginia: specific counties/cities like Bland, Buchanan, etc.; Central Virginia coverage varies)",
    "regional_variations": "Eligibility thresholds differ (e.g., 187.5% poverty in Central VA vs. 200% in Southwest); different offices, intake numbers, service emphasis; wait times likely vary due to limited staff",
    "offices_or_providers": ["Central Virginia Legal Aid Society (804-648-1012)", "Southwest Virginia Legal Aid Society", "Virginia Legal Aid Society", "9 total legal aid programs via valegalaid.org"]
  },
  "official_source": "https://www.valegalaid.org/ (VaLegalAid.org); https://selfhelp.vacourts.gov/node/33/statewide-senior-legal-helpline",
  "gotchas": ["Not a single statewide program—must identify and contact correct regional legal aid society", "Seniors get priority/advice without strict finances, but full representation limited by resources/caseload", "Income guidelines use % of federal poverty (contact for current $ amounts/table)", "Excludes certain cases (e.g., criminal, domestic violence in some offices)", "Limited lawyers (fewer than 240 statewide) lead to unserved eligible cases", "Deductions considered (e.g., medical, childcare) but verify with intake"],
  "data_shape_notes": "Delivered via 9 regional legal aid societies with varying income thresholds (125-200% FPL), senior priority exceptions; no uniform asset table or fixed benefits; statewide helpline for triage but services local"
}

